  "type": "QUIZ",
  "lessonText": "Test your understanding of the Taungoo Empire's foundations with this quiz.",
  "data": {
    "questions": [
      {
        "question": "In which century was the Taungoo Empire established?",
        "options": [
          "14th century",
          "15th century",
          "16th century",
          "17th century"
        ],
        "correctAnswer": 2,
        "explanation": "The Taungoo Empire was established in the 16th century, as referenced in the lesson content."
      },
      {
        "question": "What key characteristic enabled the Taungoo Empire to expand its influence?",
        "options": [
          "Cultural development",
          "Military prowess",
          "Trade agreements",
          "Diplomatic marriages"
        ],
        "correctAnswer": 1,
        "explanation": "Military prowess was a key characteristic of the Taungoo Empire, allowing it to maintain strength and strategic alliances."
      },
      {
        "question": "The territory of the Taungoo Empire primarily covered which modern-day country?",
        "options": [
          "Thailand",
          "Laos",
          "Myanmar",
          "Vietnam"
        ],
        "correctAnswer": 2,
        "explanation": "The Taungoo Empire's territory spanned much of present-day Myanmar, showcasing its geographic scope."
      },
      {
        "question": "What was a significant aspect of the Taungoo Empire's strategic positioning?",
        "options": [
          "Isolation from other regions",
          "Influence over Southeast Asia",
          "Focus on naval power",
          "Emphasis on agriculture"
        ],
        "correctAnswer": 1,
        "explanation": "The Taungoo Empire's strategic military positioning allowed it to exert influence over Southeast Asia."
      }
    ]
  }
}
